                       <button key={p.id} onClick={() => handleApplyPalettePreset(p)} className={`p-3 border rounded-xl flex flex-col gap-2 transition-all text-left ${activePaletteId === p.id ? 'bg-brand/10 border-brand shadow-lg' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                         <span className={`text-[9px] font-black uppercase truncate ${activePaletteId === p.id ? 'text-brand' : 'text-zinc-500'}`}>{p.name}</span>
                         <div className="flex -space-x-1">
                           {p.colors.slice(0, 4).map((c: any, i: any) => (<div key={i} className="w-3.5 h-3.5 rounded-full border border-zinc-900 shadow-sm" style={{ backgroundColor: c }} />))}
                         </div>
                       </button>
                     ))}
                  </div>
                </div>

                {/* SLIDE ATMOSPHERE */}
                <div className="space-y-4 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2 px-1"><Pipette size={14} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Atmosfera Individual</h3></div>
                  <div className="grid grid-cols-1 gap-2.5">
                    <ColorControl 
                      label="Background do Slide" 
                      value={currentSlide?.options?.background || '#0D0D0D'} 
                      onChange={(v) => updateSlideProperty(['options', 'background'], v)}
                      brandColors={activeBrandColors}
                    />
                    <ColorControl 
                      label="Texto Principal" 
                      value={currentSlide?.options?.text || '#FFFFFF'} 
                      onChange={(v) => updateSlideProperty(['options', 'text'], v)}
                      brandColors={activeBrandColors}
                    />
                    <ColorControl 
                      label="Cor de Acento (Icones/Checks)" 
                      value={currentSlide?.options?.accent || '#1fb2f7'} 
                      onChange={(v) => updateSlideProperty(['options', 'accent'], v)}
                      brandColors={activeBrandColors}
                    />
                  </div>
                </div>

                {/* COMPONENT DISSECTION */}
                <div className="space-y-4 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2 px-1"><BoxIcon size={14} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Componente: Box / Card</h3></div>
                  <div className="bg-black/20 p-4 rounded-3xl border border-white/5 space-y-3">
                    <ColorControl 
                      label="Fundo da Box" 
                      value={currentSlide?.options?.cardBg || '#1fb2f7'} 
                      onChange={(v) => updateSlideProperty(['options', 'cardBg'], v)}
                      brandColors={activeBrandColors}
                    />
                    <ColorControl 
                      label="Texto da Box" 
                      value={currentSlide?.options?.cardTextColor || '#000000'} 
                      onChange={(v) => updateSlideProperty(['options', 'cardTextColor'], v)}
                      brandColors={activeBrandColors}
                    />
                    <div className="px-1 pt-2">
                       <TransformControl 
                        label="Opacidade" 
                        value={currentSlide?.options?.cardOpacity ?? 1} 
                        min={0} max={1} step={0.05} 
                        onChange={(v) => updateSlideProperty(['options', 'cardOpacity'], v)} 
                      />
                    </div>
                  </div>
                </div>

                {/* TYPOGRAPHY */}
                <div className="space-y-4 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2 px-1"><Baseline size={14} className="text-brand" /><h3 className="text-[10px] font-black text-white uppercase tracking-widest">Tipografia</h3></div>
                  <div className="grid grid-cols-1 gap-3 px-1">
                    <div className="space-y-1.5">
                      <label className="text-[8px] font-black uppercase text-zinc-600 px-1">Fonte Base</label>
                      <select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={(e) => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-zinc-900 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none focus:border-brand/50">
                        {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                      </select>
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[8px] font-black uppercase text-zinc-600 px-1">Fonte Destaque</label>
                      <select value={currentSlide?.options?.fontDestaque || 'Instrument Serif'} onChange={(e) => updateSlideProperty(['options', 'fontDestaque'], e.target.value)} className="w-full bg-zinc-900 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none focus:border-brand/50">
                        {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                      </select>
                    </div>
                  </div>
                </div>

                {/* DIMENSIONS */}
                <div className="space-y-6 pt-6 border-t border-white/5 px-1">
                  <TransformControl label="Padding Global" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={(v) => updateSlideProperty(['options', 'padding'], v)} />
                  <TransformControl label="Espaçamento Vertical" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={(v) => updateSlideProperty(['options', 'blockGap'], v)} />
                </div>
              </div>
            ) : null}
          </div>
        </aside>

        <main className="flex-1 bg-[#121214] relative flex flex-col">
          <div className="absolute top-5 right-5 z-40 flex items-center gap-1 bg-black/30 backdrop-blur-xl p-1.5 rounded-xl border border-white/5">
            <button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-1.5 text-zinc-500 hover:text-white transition-colors"><ZoomOut size={16} /></button>
            <div className="px-2 text-[10px] font-black font-mono text-zinc-400">{(zoom * 100).toFixed(0)}%</div>
            <button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-1.5 text-zinc-500 hover:text-white transition-colors"><ZoomIn size={16} /></button>
          </div>
          <div className="flex-1 flex items-center justify-center overflow-auto p-20">
            <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">
              {carousel?.slides?.[currentIndex] && (
                <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} customFonts={carousel.customFonts} />
              )}
            </div>
          </div>
          {carousel && carousel.slides.length > 0 && (
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-6 bg-black/50 backdrop-blur-2xl px-8 py-4 rounded-full border border-white/5 shadow-2xl">
              <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5"><ChevronLeft size={20}/></button>
              <div className="flex gap-2.5">
                {carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}
              </div>
              <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5"><ChevronRight size={20}/></button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface BoxRendererProps {
  block: Block;
  theme: Theme;
  isGridMember?: boolean;
  indexInGrid?: number;
  onEditIcon?: (block: Block) => void;
}

export function BoxRenderer({ block, theme, isGridMember, indexInGrid = 0, onEditIcon }: BoxRendererProps) {
  const text = (block.content || '') as string;
  const iconName = block.options?.icon;
  const customIcon = block.options?.customIcon;
  const variant = block.options?.variant || 'default';
  const align = block.options?.align || (isGridMember ? 'center' : 'left');
  const hasBgHighlight = text.includes('[[');
  const customPadding = block.options?.padding;
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  const renderRichText = (input: string) => {
    let parts: (string | React.ReactNode)[] = [input];
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(<span key={`bg-hl-${i}`} className="inline px-4 py-1 rounded-xl mx-1 font-black" style={{ backgroundColor: theme.colors.hlBgColor || '#fff', color: theme.colors.hlTextColor || '#000', WebkitBoxDecorationBreak: 'clone', boxDecorationBreak: 'clone' as any, fontFamily: theme.typography.fontFamily }}>{s}</span>);
            } else if (s !== "") { newParts.push(s); }
          });
        } else { newParts.push(part); }
      });
      parts = newParts;
    }
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) { finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>); }
          else if (s !== "") { finalParts.push(s); }
        });
      } else { finalParts.push(part); }
    });
    return finalParts;
  };

  const isOutlined = variant === 'outlined';
  const isPill = variant === 'pill';
  const shouldReverseIcon = !isGridMember && indexInGrid % 2 === 1;
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;

  const bgColor = isOutlined ? 'transparent' : (block.options?.color ? `${block.options.color}20` : (theme.colors.cardBg || theme.colors.accent));
  // Individual dissection check: prioritize global theme cardTextColor then slide text then black.
  const textColor = block.options?.color || theme.colors.cardTextColor || (isOutlined ? theme.colors.textPrimary : '#000000');

  const renderIcon = () => {
    const size = isGridMember ? 80 : (isPill ? 50 : 120);
    const renderSize = block.options?.fontSize ? block.options.fontSize * 1.5 : size;

    if (customIcon) {
       if (customIcon.startsWith('<svg')) return (<div style={{ width: renderSize, height: renderSize }} className="flex items-center justify-center" dangerouslySetInnerHTML={{ __html: customIcon }} />);
       if (customIcon.startsWith('http') || customIcon.startsWith('data:image')) return <img src={customIcon} style={{ width: renderSize, height: renderSize }} className="object-contain rounded-xl" alt="icon" />;
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={renderSize} strokeWidth={1.5} />;
    }
    if (iconName) {
      const IconComponent = (Icons as any)[iconName];
      if (IconComponent) return <IconComponent size={renderSize} strokeWidth={1.5} />;
    }
    return null;
  };

  if (isPill) {
     return (
        <div className="relative w-full p-12 rounded-[100px] flex items-center transition-all overflow-hidden border border-white/5 shadow-2xl" style={{ backgroundColor: bgColor, color: textColor, textAlign: 'left', fontFamily: selectedFont }}>
           <div className="flex-1">
              <h4 className="text-[38px] font-black leading-tight tracking-tight mb-2 uppercase italic">{renderRichText(text)}</h4>
           </div>
           <div className="w-16 h-16 rounded-full border-2 border-current opacity-30 flex items-center justify-center shrink-0">
              <Icons.ArrowUpRight size={32} strokeWidth={2.5} />
           </div>
        </div>
     );
  }

  const paddingValue = customPadding !== undefined ? `${customPadding}px` : '48px';
  const fontSize = block.options?.fontSize ? `${block.options.fontSize}px` : '34px';

  return (
    <div 
      className={`relative rounded-[60px] flex flex-col transition-all overflow-hidden justify-center ${isOutlined ? 'border-[4px]' : ''} ${isGridMember ? 'w-full h-full' : 'w-fit'}`} 
      style={{ 
        padding: paddingValue,
        backgroundColor: bgColor, 
        opacity: isOutlined ? 1 : opacity, 
        borderColor: theme.colors.accent, 
        color: textColor, 
        textAlign: align === 'center' ? 'center' : 'left',
        fontFamily: selectedFont
      }}
    >
      <div className={`flex items-center gap-6 ${align === 'center' ? 'flex-col' : (shouldReverseIcon ? 'flex-row-reverse' : 'flex-row')}`}>
        <div onClick={() => onEditIcon?.(block)} className="group relative cursor-pointer shrink-0">
          <div className="opacity-100 group-hover:opacity-70 transition-opacity">{renderIcon()}</div>
          <div className="absolute inset-[-15px] bg-brand/20 border-2 border-brand rounded-3xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
             <Icons.Edit3 size={32} className="text-brand" />
          </div>
        </div>
        <div 
          className={`${hasBgHighlight ? '!leading-[1.5]' : '!leading-[1.2]'} tracking-tight font-black uppercase ${align === 'center' ? 'mt-4' : ''}`}
          style={{ fontSize }}
        >
          {renderRichText(text)}
        </div>
      </div>
    </div>
  );
}
